create or replace function public._trim_session_turns_jsonb(p_turns jsonb, p_max integer)
returns jsonb
language sql
immutable
as $$
  select coalesce(
    (
      select jsonb_agg(elem order by ord asc)
      from (
        select elem, ord
        from (
          select elem, ord,
            row_number() over (order by ord desc) as rn
          from jsonb_array_elements(coalesce(p_turns, '[]'::jsonb))
            with ordinality as t(elem, ord)
        ) ranked
        where rn <= p_max
      ) kept
    ),
    '[]'::jsonb
  );
$$;

