create or replace function public.append_ai_chat_session_turns(
  p_project_id uuid,
  p_chat_id uuid,
  p_user_text text,
  p_assistant_text text
)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_ai text;
  v_max_msg_len integer := 2000;
  v_max_turns integer := 10;
  v_user text;
  v_asst text;
  v_merged jsonb;
  v_trimmed jsonb;
begin
  if v_uid is null then
    return;
  end if;

  if not public.can_access_project(p_project_id) then
    return;
  end if;

  v_ai := public.effective_ai_access_for_profile(p_project_id);
  if v_ai is null or v_ai = 'none' then
    return;
  end if;

  v_user := left(coalesce(p_user_text, ''), v_max_msg_len);
  v_asst := left(coalesce(p_assistant_text, ''), v_max_msg_len);

  update public.project_ai_chat_sessions s
  set
    recent_turns = public._trim_session_turns_jsonb(
      coalesce(s.recent_turns, '[]'::jsonb) || jsonb_build_array(
        jsonb_build_object('role', 'user', 'text', v_user),
        jsonb_build_object('role', 'assistant', 'text', v_asst)
      ),
      v_max_turns
    ),
    updated_at = now()
  where s.chat_id = p_chat_id
    and s.project_id = p_project_id
    and s.profile_id = v_uid;

  if found then
    return;
  end if;

  if exists (
    select 1
    from public.project_ai_chat_sessions s2
    where s2.chat_id = p_chat_id
  ) then
    return;
  end if;

  v_merged := jsonb_build_array(
    jsonb_build_object('role', 'user', 'text', v_user),
    jsonb_build_object('role', 'assistant', 'text', v_asst)
  );
  v_trimmed := public._trim_session_turns_jsonb(v_merged, v_max_turns);

  insert into public.project_ai_chat_sessions (
    chat_id,
    project_id,
    profile_id,
    recent_turns,
    rolling_summary,
    updated_at
  )
  values (
    p_chat_id,
    p_project_id,
    v_uid,
    v_trimmed,
    null,
    now()
  );
end;
$$;

revoke all on function public.append_ai_chat_session_turns(uuid, uuid, text, text) from public;
grant execute on function public.append_ai_chat_session_turns(uuid, uuid, text, text) to authenticated;
